const { getReq } = require('@meli/server-context');

const buildContext = require('./build-context');
const buildStarterContext = require('./build-flow-context');

const buildAutomaticContext = () => {
  try {
    const req = getReq();

    if (req) {
      return buildContext(req);
    }

    return buildStarterContext();
  } catch (error) {
    return null;
  }
};

module.exports = {
  buildAutomaticContext,
};
